class Solution {
public:
    int numberOfSpecialChars(string word) {
        unordered_map<char, int> firstUppercaseIndex;
        unordered_set<char> lowercaseChars;

        for (int i = 0; i < word.size(); ++i) {
            char c = word[i];
            if (islower(c)) {
                lowercaseChars.insert(c);
            } else {
                char lowerC = tolower(c);
                if (firstUppercaseIndex.find(lowerC) == firstUppercaseIndex.end()) {
                    firstUppercaseIndex[lowerC] = i;
                }
            }
        }

        int count = 0;
        for (char c : lowercaseChars) {
            if (firstUppercaseIndex.find(c) != firstUppercaseIndex.end()) {
                bool isSpecial = true;
                for (int i = firstUppercaseIndex[c] + 1; i < word.size(); ++i) {
                    if (word[i] == c) {
                        isSpecial = false;
                        break;
                    }
                }
                if (isSpecial) {
                    count++;
                }
            }
        }

        return count;
    }
};
